ვას"],"correct_option":"A","explanation":"259² მუხლი პირდაპირ ეხება კულტურული მემკვიდრეობის დაზიანებას ან განადგურებას.","law_article":"მუხლი 259²"},{"text":"რომელი რეჟიმის დარღვევას ეხება სსკ-ის 259³ მუხლი?","options":["კულტურული მემკვიდრეობის დამცავი ზონის რეჟიმის","საბაჟო კონტროლის რეჟიმის","კარანტინის რეჟიმის","იზოლაციის რეჟიმის"],"correct_option":"A","explanation":"259³ მუხლი ითვალისწინებს კულტურული მემკვიდრეობის დამცავი ზონის რეჟიმის დარღვევას.","law_article":"მუხლი 259³"},{"text":"რას ეხება სსკ-ის 259⁴ მუხლი?","options":["ძეგლებისა და სხვა კულტურული ფასეულობების საქართველოდან უნებართვო გატანას","კულტურული ძეგლის საქართველოში შემოტანას","საბაჟო დეკლარაციის შევსებას","არქეოლოგიური ობიექტის დაცვას"],"correct_option":"A","explanation":"259⁴ მუხლი ეხება ძეგლებისა და სხვა კულტურული ფასეულობების საქართველოდან უნებართვო გატანას.","law_article":"მუხლი 259⁴"},{"text":"რას ეხება სსკ-ის 259⁵ მუხლი?","options":["შეიარაღებული კონფლიქტების დროს კულტურულ ფასეულობათა დაცვის საერთაშორისო წესების დარღვევას","სამშვიდობო კულტურული ღონისძიების ჩატარებას","კულტურული ობიექტის რესტავრაციას","კულტურული მემკვიდრეობის აღწერას"],"correct_option":"A","explanation":"259⁵ მუხლი ითვალისწინებს შეიარაღებული კონფლიქტების დროს კულტურულ ფასეულობათა დაცვის საერთაშორისო წესების დარღვევას.","law_article":"მუხლი 259⁵"}]$questions$::jsonb)
  loop
    select id into v_question_id
    from public.questions
    where law_id = v_law_id
      and text = r.question->>'text';

    if v_question_id is null then
      select id into v_article_id
      from public.law_articles
      where law_id = v_law_id
        and article_number = regexp_replace(
          r.question->>'law_article',
          '^(მუხლი[[:space:]]+[^,[:space:]]+).*$',
          '\1'
        );

      insert into public.questions (
        category_id, subcategory_id, law_id, primary_law_article_id, text, difficulty,
        explanation, law_name, law_article, source_url, law_version_date,
        needs_review, is_prime, is_published
      )
      values (
        v_category_id, v_subcategory_id, v_law_id, v_article_id,
        r.question->>'text', 'hard', r.question->>'explanation',
        'საქართველოს სისხლის სამართლის კოდექსი', r.question->>'law_article',
        v_source_url, v_version_date, true, false, false
      )
      returning id into v_question_id;

      insert into public.question_options (question_id, option_text, is_correct, sort_order)
      select
        v_question_id,
        option.value,
        case option.ordinality
          when 1 then r.question->>'correct_option' = 'A'
          when 2 then r.question->>'correct_option' = 'B'
          when 3 then r.question->>'correct_option' = 'C'
          when 4 then r.question->>'correct_option' = 'D'
        end,
        option.ordinality
      from jsonb_array_elements_text(r.question->'options') with ordinality as option(value, ordinality);

      if v_article_id is not null then
        insert into public.question_law_articles (question_id, law_article_id, is_primary)
        values (v_question_id, v_article_id, true)
        on conflict (question_id, law_article_id) do nothing;
      end if;
    end if;
  end loop;
end $$;
